// HITL Timeout Auto-Publish: post to X via OAuth 1.0a
const crypto = require("crypto");
const https = require("https");

const sessionData = $input.first().json;
const tweetText = sessionData.payload_draft || '';
const notionBlockId = sessionData.payload_notion_block_id || '';
const topic = sessionData.payload_topic || 'General';
const callbackId = sessionData.callback_id || '';
const sessionId = sessionData.id || '';

if (!tweetText) {
  return [{ json: { error: 'No draft in session', callbackId } }];
}

const consumerKey = "__X_CONSUMER_KEY__";
const consumerSecret = "__X_CONSUMER_SECRET__";
const accessToken = "__X_ACCESS_TOKEN__";
const accessTokenSecret = "__X_ACCESS_TOKEN_SECRET__";

const method = "POST";
const url = "https://api.twitter.com/2/tweets";
const oauthTimestamp = Math.floor(Date.now() / 1000).toString();
const oauthNonce = crypto.randomBytes(16).toString("hex");

const oauthParams = {
  oauth_consumer_key: consumerKey,
  oauth_nonce: oauthNonce,
  oauth_signature_method: "HMAC-SHA1",
  oauth_timestamp: oauthTimestamp,
  oauth_token: accessToken,
  oauth_version: "1.0"
};

const sortedParams = Object.keys(oauthParams).sort().map(k =>
  `${encodeURIComponent(k)}=${encodeURIComponent(oauthParams[k])}`
).join("&");

const sigBase = `${method}&${encodeURIComponent(url)}&${encodeURIComponent(sortedParams)}`;
const sigKey = `${encodeURIComponent(consumerSecret)}&${encodeURIComponent(accessTokenSecret)}`;
const signature = crypto.createHmac("sha1", sigKey).update(sigBase).digest("base64");

const authHeader = "OAuth " + [...Object.keys(oauthParams).sort().map(k =>
  `${encodeURIComponent(k)}="${encodeURIComponent(oauthParams[k])}"`)
  , `oauth_signature="${encodeURIComponent(signature)}"`].join(", ");

return new Promise((resolve, reject) => {
  const body = JSON.stringify({ text: tweetText });
  const options = {
    method,
    headers: {
      "Authorization": authHeader,
      "Content-Type": "application/json",
      "Content-Length": Buffer.byteLength(body)
    }
  };
  const req = https.request(url, options, (res) => {
    let data = "";
    res.on("data", chunk => data += chunk);
    res.on("end", () => {
      try {
        const parsed = JSON.parse(data);
        if (parsed.data && parsed.data.id) {
          resolve([{ json: {
            tweet_id: parsed.data.id,
            tweet_text: tweetText,
            tweet_url: `https://x.com/i/web/status/${parsed.data.id}`,
            topic,
            notionBlockId,
            callbackId,
            sessionId,
            auto_published: true,
            published_at: new Date().toISOString()
          } }]);
        } else {
          resolve([{ json: { error: JSON.stringify(parsed), tweetText, callbackId } }]);
        }
      } catch(e) {
        resolve([{ json: { error: data, callbackId } }]);
      }
    });
  });
  req.on("error", reject);
  req.write(body);
  req.end();
});

// Prepare data for published_posts INSERT
// Sprawdz czy post zostal opublikowany (tweet_id musi istniec)
const data = $input.first().json;

if (!data.tweet_id || data.error) {
  const errMsg = data.error || 'No tweet_id returned from X API';
  throw new Error('X API error: ' + errMsg);
}

const tweetText = (data.tweet_text || '').replace(/'/g, "''");
const topic = (data.topic || 'General').replace(/'/g, "''");
const notionBlockId = (data.notionBlockId || '').replace(/'/g, "''");
const tweetUrl = (data.tweet_url || '').replace(/'/g, "''");
const tweetId = (data.tweet_id || '').replace(/'/g, "''");
const callbackId = (data.callbackId || '').replace(/'/g, "''");
return [{ json: {
  tweet_text_esc: tweetText,
  topic_esc: topic,
  notionBlockId_esc: notionBlockId,
  tweet_url_esc: tweetUrl,
  tweet_id_esc: tweetId,
  callbackId_esc: callbackId,
  tweet_id: data.tweet_id,
  tweet_url: data.tweet_url,
  tweet_text: data.tweet_text,
  notionBlockId: data.notionBlockId,
  callbackId: data.callbackId
} }];

